const API_KEY = process.env.REACT_APP_OMDB_API_KEY;
const BASE_URL = "https://www.omdbapi.com/";

// Create a constant for the fallback so it's easy to change in one place
const FALLBACK_POSTER = "https://placehold.co";

export const searchMovies = async (term) => {
    if (!API_KEY) {
        console.error("API Key is missing!");
        return [];
    }

    try {
        const response = await fetch(`${BASE_URL}?s=${term}&apikey=${API_KEY}`);
        const data = await response.json();

        if (data.Search) {
            const uniqueMovies = data.Search.filter(
                (movie, index, self) =>
                    index === self.findIndex((m) => m.imdbID === movie.imdbID)
            );

            return uniqueMovies.map((movie) => ({
                id: movie.imdbID,
                title: movie.Title,
                // ✅ Changed to reliable placehold.co
                poster: movie.Poster !== "N/A" ? movie.Poster : FALLBACK_POSTER
            }));
        }
        return [];
    } catch (error) {
        console.error("Fetch error:", error);
        return [];
    }
};

export const getMovieDetails = async (id) => {
    if (!API_KEY) return null;

    try {
        const response = await fetch(`${BASE_URL}?i=${id}&apikey=${API_KEY}&plot=full`);
        const data = await response.json();

        if (data.Response === "True") {
            return {
                id: data.imdbID,
                title: data.Title,
                // ✅ Changed to reliable placehold.co
                poster: data.Poster !== "N/A" ? data.Poster : FALLBACK_POSTER,
                plot: data.Plot,
                rating: data.imdbRating,
                director: data.Director,
                actors: data.Actors,
                genre: data.Genre,
            };
        }

        return null;
    } catch (error) {
        console.error("Detail Fetch error:", error);
        return null;
    }
};
